// Format & dedupe Slack messages from #ai-roundup
// Input: Slack messages (channel:history) for the last ~2 hours
// Cross-ref: existing topics from the Topics sheet (for dedup)
// Output: only NEW Jarvis-authored topics, ready to append

const messages = $input.all();

// Build a Set of existing topic strings (lowercased + trimmed) for dedup
const existing = $('Get Existing Topics for Dedup').all()
  .map(row => String(row.json['Topic'] || '').trim().toLowerCase())
  .filter(t => t.length > 0);
const seen = new Set(existing);

const today = new Date().toISOString().split('T')[0];
const out = [];

for (const item of messages) {
  const msg = item.json;

  // Identify Jarvis as author. Slack bot messages may carry the bot name
  // in either msg.username (Incoming Webhook style) or msg.bot_profile.name
  // (chat.postMessage from a real bot user).
  const author = msg.username || msg.bot_profile?.name || '';
  if (author !== 'Jarvis') continue;

  const text = msg.text || '';
  if (!text || !text.trim()) continue;

  // Strip Slack formatting
  let topic = text
    .replace(/<@[A-Z0-9]+>/g, '')              // user mentions
    .replace(/<#[A-Z0-9]+\|[^>]+>/g, '')       // channel mentions
    .replace(/<([^|>]+)\|([^>]+)>/g, '$2')     // <url|title> -> title
    .replace(/<(https?:[^>]+)>/g, '$1')        // bare <url>
    .replace(/\n+/g, ' ')                      // flatten newlines
    .trim();

  if (topic.length < 10) continue;
  if (topic.length > 500) topic = topic.substring(0, 497) + '...';

  // Dedup against the sheet AND within this run
  const key = topic.toLowerCase();
  if (seen.has(key)) continue;
  seen.add(key);

  out.push({
    json: {
      topic,
      dateAdded: today,
      source: 'Slack'
    }
  });
}

return out;

// Find topics where Date Added is older than 7 days, then delete them —
// used AND unused alike. Used topics are kept long enough to publish, then
// cleaned up so the sheet doesn't bloat. Sort descending by row number so
// we delete from the bottom up (prevents row shifting from breaking subsequent deletes).

const rows = $input.all();
const now = new Date();
const sevenDaysAgo = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);

const toDelete = rows
  .filter(row => {
    const dateAdded = row.json['Date Added'];

    // Skip rows without a parseable Date Added (e.g. manually added without metadata)
    if (!dateAdded || String(dateAdded).trim() === '') return false;

    const addedDate = new Date(dateAdded);
    if (isNaN(addedDate.getTime())) return false;

    return addedDate < sevenDaysAgo;
  })
  .sort((a, b) => {
    const rowA = a.json['row_number'] || a.json['_rowNumber'] || 0;
    const rowB = b.json['row_number'] || b.json['_rowNumber'] || 0;
    return rowB - rowA; // descending
  });

// CRITICAL: return an empty array (not a placeholder item) when nothing's expired.
// An empty array makes the downstream Delete node not run at all. A placeholder
// item would push the Delete node into a Bad Request ("can't delete all rows")
// because rowNumber would be undefined.
return toDelete.map(row => ({
  json: {
    rowNumber: row.json['row_number'] || row.json['_rowNumber'],
    topic: row.json['Topic'],
    dateAdded: row.json['Date Added'],
    lastUsed: row.json['Last Used'] || null
  }
}));

// Parse AI Agent JSON output, dedupe against existing sheet topics, output new ones
const raw = $input.first().json.output || $input.first().json.message?.content || $input.first().json.content || $input.first().json;

let parsed;
try {
  const cleaned = typeof raw === 'string' ? raw.replace(/```json\n?|```\n?/g, '').trim() : raw;
  parsed = typeof cleaned === 'string' ? JSON.parse(cleaned) : cleaned;
} catch (e) {
  throw new Error('LLM did not return valid JSON: ' + raw);
}

const generated = Array.isArray(parsed) ? parsed : (parsed.topics || []);
if (!Array.isArray(generated)) {
  throw new Error('Expected an array of topics in the LLM output, got: ' + JSON.stringify(parsed));
}

// Build dedup set from existing sheet topics (case-insensitive)
const existing = $('Get Existing Topics for AI Gen').all()
  .map(row => String(row.json['Topic'] || '').trim().toLowerCase())
  .filter(t => t.length > 0);
const seen = new Set(existing);

const today = new Date().toISOString().split('T')[0];
const out = [];

for (const t of generated) {
  let topic = String(t || '').trim();
  if (!topic || topic.length < 10) continue;
  if (topic.length > 500) topic = topic.substring(0, 497) + '...';

  const key = topic.toLowerCase();
  if (seen.has(key)) continue;
  seen.add(key);

  out.push({
    json: {
      topic,
      dateAdded: today,
      source: 'AI Generator'
    }
  });
}

return out;
